const DomUtils={get:(id)=>document.getElementById(id),query:(selector)=>document.querySelector(selector),queryAll:(selector)=>document.querySelectorAll(selector),addClass:(element,className)=>element.classList.add(className),removeClass:(element,className)=>element.classList.remove(className),toggleClass:(element,className)=>element.classList.toggle(className),show:(element)=>element.style.display='block',hide:(element)=>element.style.display='none',toggle:(element)=>{if(element.style.display==='none'){element.style.display='block';}else{element.style.display='none';}}};const DateUtils={format:(date,format='dd.mm.yyyy')=>{const d=new Date(date);const day=d.getDate().toString().padStart(2,'0');const month=(d.getMonth()+1).toString().padStart(2,'0');const year=d.getFullYear();return format.replace('dd',day).replace('mm',month).replace('yyyy',year);},diffDays:(date1,date2)=>{const d1=new Date(date1);const d2=new Date(date2);const diffTime=Math.abs(d2-d1);return Math.ceil(diffTime/(1000*60*60*24));},isOverdue:(date)=>{return new Date(date)<new Date();}};const Notify={show:(message,type='info',duration=3000)=>{const alert=document.createElement('div');alert.className=`alert alert-${type} fade-in`;alert.innerHTML=`
            <i class="bi bi-${type === 'success' ? 'check-circle' : 
                                 type === 'danger' ? 'exclamation-circle' :
                                 type === 'warning' ? 'exclamation-triangle' :
                                 'info-circle'}"></i>
            ${message}
        `;const container=DomUtils.query('.alerts-container')||document.body;container.appendChild(alert);setTimeout(()=>{alert.remove();},duration);},success:(message)=>Notify.show(message,'success'),error:(message)=>Notify.show(message,'danger'),warning:(message)=>Notify.show(message,'warning'),info:(message)=>Notify.show(message,'info')};const Ajax={get:async(url)=>{try{const response=await fetch(url);return await response.json();}catch(error){console.error('GET error:',error);Notify.error('Ошибка при загрузке данных');}},post:async(url,data)=>{try{const response=await fetch(url,{method:'POST',headers:{'Content-Type':'application/json','X-CSRFToken':getCookie('csrftoken')},body:JSON.stringify(data)});return await response.json();}catch(error){console.error('POST error:',error);Notify.error('Ошибка при отправке данных');}},postForm:async(url,formData)=>{try{const response=await fetch(url,{method:'POST',headers:{'X-CSRFToken':getCookie('csrftoken')},body:formData});return await response.json();}catch(error){console.error('POST Form error:',error);Notify.error('Ошибка при отправке формы');}}};function getCookie(name){let cookieValue=null;if(document.cookie&&document.cookie!==''){const cookies=document.cookie.split(';');for(let i=0;i<cookies.length;i++){const cookie=cookies[i].trim();if(cookie.substring(0,name.length+1)===(name+'=')){cookieValue=decodeURIComponent(cookie.substring(name.length+1));break;}}}
return cookieValue;}
document.addEventListener('DOMContentLoaded',()=>{console.log('Main.js loaded');const alertsContainer=document.createElement('div');alertsContainer.className='alerts-container';alertsContainer.style.cssText=`
        position: fixed;
        top: 20px;
        right: 20px;
        z-index: 9999;
        max-width: 400px;
    `;document.body.appendChild(alertsContainer);});window.DomUtils=DomUtils;window.DateUtils=DateUtils;window.Notify=Notify;window.Ajax=Ajax;;let currentSubtaskId=null;let currentProductIndex=null;function assignProductPerformers(subtaskId,productIndex){currentSubtaskId=subtaskId;currentProductIndex=productIndex;var myModal=new bootstrap.Modal(document.getElementById('assignPerformersModal'));myModal.show();}
function saveProductPerformers(){alert('Функция сохранения исполнителей будет реализована позже');bootstrap.Modal.getInstance(document.getElementById('assignPerformersModal')).hide();}
$(document).ready(function(){$('#productPerformers').select2({theme:'bootstrap-5',width:'100%',placeholder:'Выберите исполнителей...'});$('#productResponsible').select2({theme:'bootstrap-5',width:'100%',placeholder:'Выберите ответственного...'});});;